import{_ as s,o as i,c as t,ae as e}from"./chunks/framework.6LiUpjzz.js";const k=JSON.parse('{"title":"Flask 서버 실행하기 (대시보드)","description":"","frontmatter":{},"headers":[],"relativePath":"guide/flask-server.md","filePath":"guide/flask-server.md"}'),n={name:"guide/flask-server.md"};function l(o,a,h,r,p,d){return i(),t("div",null,[...a[0]||(a[0]=[e('<h1 id="flask-서버-실행하기-대시보드" tabindex="-1">Flask 서버 실행하기 (대시보드) <a class="header-anchor" href="#flask-서버-실행하기-대시보드" aria-label="Permalink to &quot;Flask 서버 실행하기 (대시보드)&quot;">​</a></h1><div class="warning custom-block"><p class="custom-block-title">이 문서 사이트에서는 서버가 돌아가지 않습니다</p><p>지금 보시는 페이지는 <strong>GitHub Pages에 올라간 정적 매뉴얼</strong>입니다. <strong>Flask는 여기서 실행할 수 없고</strong>, 반드시 <strong>프로젝트를 받아 둔 자신의 Windows PC</strong>에서 아래 순서대로 실행합니다.<br> 코드 블록 우측의 <strong>복사</strong> 버튼으로 명령을 붙여 넣을 수 있습니다.</p></div><h2 id="_1-준비물" tabindex="-1">1. 준비물 <a class="header-anchor" href="#_1-준비물" aria-label="Permalink to &quot;1. 준비물&quot;">​</a></h2><ul><li>Windows PC (대시보드·Wi‑Fi 도구는 Windows 전제)</li><li><a href="https://www.python.org/downloads/" target="_blank" rel="noreferrer">Python 3</a> 설치 (<code>python</code>이 터미널에서 인식되어야 함)</li><li>이 저장소 폴더 전체 (클론 또는 ZIP 해제)</li></ul><p>선택:</p><ul><li>ARP 정밀 스캔: <a href="https://npcap.com/" target="_blank" rel="noreferrer">Npcap</a></li><li>가상환경 권장: 아래 <code>venv</code> 단계</li></ul><h2 id="_2-가장-빠른-방법-배치-파일" tabindex="-1">2. 가장 빠른 방법 (배치 파일) <a class="header-anchor" href="#_2-가장-빠른-방법-배치-파일" aria-label="Permalink to &quot;2. 가장 빠른 방법 (배치 파일)&quot;">​</a></h2><p>저장소 <strong>루트 폴더</strong>에서 다음 중 하나를 더블클릭하거나 실행합니다.</p><table tabindex="0"><thead><tr><th>파일</th><th>설명</th></tr></thead><tbody><tr><td><strong><code>run_dashboard.bat</code></strong></td><td>경로·한글 폴더·venv 자동 처리, Flask용 CMD 창 + 브라우저 자동 실행</td></tr><tr><td><strong><code>대시보드 열기.bat</code></strong></td><td>위 파일을 <code>pushd</code>로 호출 (같은 동작)</td></tr></tbody></table><p>실행 후:</p><ol><li>제목이 <strong><code>NetWork-IP Flask 8500</code></strong> 인 검은 CMD 창이 떠 있어야 합니다. <strong>이 창을 닫으면 서버가 꺼집니다.</strong></li><li>브라우저에서 <strong><code>http://127.0.0.1:8500</code></strong></li><li>Wi‑Fi 전용 화면: <strong><code>http://127.0.0.1:8500/wifi</code></strong></li></ol><p>배치 파일 시작 시 콘솔에 <strong>같은 Wi‑Fi용 <code>http://&lt;IPv4&gt;:8500</code></strong> 주소가 함께 출력됩니다. 휴대폰 등에서 쓰려면 Windows <strong>방화벽에서 포트 8500 인바운드 허용</strong>이 필요할 수 있습니다.</p><h2 id="_3-수동-실행-터미널" tabindex="-1">3. 수동 실행 (터미널) <a class="header-anchor" href="#_3-수동-실행-터미널" aria-label="Permalink to &quot;3. 수동 실행 (터미널)&quot;">​</a></h2><p>프로젝트 루트에서:</p><h3 id="_3-1-가상환경-의존성-최초-1회" tabindex="-1">3-1) 가상환경 + 의존성 (최초 1회) <a class="header-anchor" href="#_3-1-가상환경-의존성-최초-1회" aria-label="Permalink to &quot;3-1) 가상환경 + 의존성 (최초 1회)&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> venv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .venv</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">.venv\\Scripts\\activate</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> requirements.txt</span></span></code></pre></div><h3 id="_3-2-서버-기동" tabindex="-1">3-2) 서버 기동 <a class="header-anchor" href="#_3-2-서버-기동" aria-label="Permalink to &quot;3-2) 서버 기동&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">.venv\\Scripts\\activate</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app.py</span></span></code></pre></div><p>또는 venv 없이 전역 Python만 쓰는 경우:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> requirements.txt</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app.py</span></span></code></pre></div><p>정상 기동 시 터미널에 Flask가 리스닝한다는 메시지가 나오고, 브라우저로 <strong><code>http://127.0.0.1:8500</code></strong> 을 엽니다.</p><h2 id="_4-포트-바꾸기" tabindex="-1">4. 포트 바꾸기 <a class="header-anchor" href="#_4-포트-바꾸기" aria-label="Permalink to &quot;4. 포트 바꾸기&quot;">​</a></h2><p>기본 포트는 <strong>8500</strong> 입니다. 다른 포트를 쓰려면 환경 변수를 설정한 뒤 <code>app.py</code>를 실행합니다.</p><p><strong>PowerShell 예시:</strong></p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">env:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">NETWORK_IP_SEARCH_PORT </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;8080&quot;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python app.py</span></span></code></pre></div><p><strong>CMD 예시:</strong></p><div class="language-bat vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bat</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">set</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> NETWORK_IP_SEARCH_PORT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8080</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python app.py</span></span></code></pre></div><p>그다음 브라우저에서는 <code>http://127.0.0.1:8080</code> 으로 접속합니다.</p><h2 id="_5-자주-나오는-문제" tabindex="-1">5. 자주 나오는 문제 <a class="header-anchor" href="#_5-자주-나오는-문제" aria-label="Permalink to &quot;5. 자주 나오는 문제&quot;">​</a></h2><h3 id="python을-찾을-수-없음" tabindex="-1"><code>python</code>을 찾을 수 없음 <a class="header-anchor" href="#python을-찾을-수-없음" aria-label="Permalink to &quot;`python`을 찾을 수 없음&quot;">​</a></h3><ul><li>Python 설치 시 <strong>“Add python.exe to PATH”</strong> 옵션을 켰는지 확인하거나, <strong>시작 메뉴 → Python</strong>에서 “Python 3.x” 경로를 확인해 전체 경로로 실행합니다.</li></ul><h3 id="address-already-in-use-포트-충돌" tabindex="-1"><code>Address already in use</code> / 포트 충돌 <a class="header-anchor" href="#address-already-in-use-포트-충돌" aria-label="Permalink to &quot;`Address already in use` / 포트 충돌&quot;">​</a></h3><ul><li>다른 프로그램이 8500을 쓰 중입니다. 위 <strong>4. 포트 바꾸기</strong>로 다른 포트를 지정하거나, 기존에 떠 있는 Flask/CMD 창을 종료합니다.</li></ul><h3 id="배치-파일은-되는데-python-app-py만-실패" tabindex="-1">배치 파일은 되는데 <code>python app.py</code>만 실패 <a class="header-anchor" href="#배치-파일은-되는데-python-app-py만-실패" aria-label="Permalink to &quot;배치 파일은 되는데 `python app.py`만 실패&quot;">​</a></h3><ul><li>현재 폴더가 <strong>프로젝트 루트</strong>( <code>app.py</code>가 있는 곳)인지 확인합니다.</li><li>Google Drive 동기화 중이면 <strong>동기 완료·오프라인 사용 가능</strong>으로 만든 뒤 다시 시도합니다.</li></ul><h3 id="같은-wi‐fi-휴대폰에서-안-열림" tabindex="-1">같은 Wi‑Fi 휴대폰에서 안 열림 <a class="header-anchor" href="#같은-wi‐fi-휴대폰에서-안-열림" aria-label="Permalink to &quot;같은 Wi‑Fi 휴대폰에서 안 열림&quot;">​</a></h3><ul><li>PC 방화벽 <strong>인바운드 규칙</strong>에서 TCP <strong>8500</strong>(또는 바꾼 포트) 허용</li><li>주소는 <strong><code>http://127.0.0.1</code></strong> 이 아니라 PC의 <strong><code>http://192.168.x.x:8500</code></strong> (배치 파일 출력 또는 <code>ipconfig</code>로 확인)</li></ul><h2 id="_6-다음-단계" tabindex="-1">6. 다음 단계 <a class="header-anchor" href="#_6-다음-단계" aria-label="Permalink to &quot;6. 다음 단계&quot;">​</a></h2><ul><li>기능 개요·주의사항: <a href="./getting-started.html">시작하기</a></li><li>스위치 포트(IF-MIB·Cisco SSH 보조): <a href="./switch-ports.html">스위치 포트 가이드</a></li><li>REST API: <a href="./../reference/api.html">API 레퍼런스</a></li></ul>',39)])])}const g=s(n,[["render",l]]);export{k as __pageData,g as default};
